"use client";

import { useState, useEffect } from "react";
import { Button, Input, Select, Textarea, Card } from "@/components/ui";
import { useAuthStore } from "@/lib/store/authStore";
import { ordersApi } from "@/lib/api/orders";
import type { CreateOrderRequest } from "@/types";

const ZONES = [
  { value: "", label: "Select zone" },
  { value: "1", label: "Mainland" },
  { value: "2", label: "Island" },
  { value: "3", label: "Expanding" },
];

export function CreateOrderForm() {
  const user = useAuthStore((state) => state.user);
  
  const [formData, setFormData] = useState<CreateOrderRequest>({
    sender_name: user?.name || "",
    sender_phone: user?.phone || "",
    pickup_address: user?.default_address || "",
    receiver_name: "",
    receiver_phone: "",
    delivery_address: "",
    package_description: "",
    zone_id: undefined,
    distance_km: undefined,
  });
  
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState<{
    tracking_number: string;
    price: number;
  } | null>(null);

  // Auto-fill sender info when user data loads
  useEffect(() => {
    if (user) {
      setFormData((prev) => ({
        ...prev,
        sender_name: user.name || prev.sender_name,
        sender_phone: user.phone || prev.sender_phone,
        pickup_address: user.default_address || prev.pickup_address,
      }));
    }
  }, [user]);

  const handleChange = (
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]:
        name === "zone_id" || name === "distance_km"
          ? value
            ? Number(value)
            : undefined
          : value,
    }));
    setError("");
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    try {
      const response = await ordersApi.createOrder(formData);
      
      if (response.success) {
        setSuccess({
          tracking_number: response.data.tracking_number,
          price: response.data.price,
        });
        
        // Reset form but keep sender info
        setFormData({
          sender_name: user?.name || "",
          sender_phone: user?.phone || "",
          pickup_address: user?.default_address || "",
          receiver_name: "",
          receiver_phone: "",
          delivery_address: "",
          package_description: "",
          zone_id: undefined,
          distance_km: undefined,
        });
      } else {
        setError(response.message || "Failed to create order");
      }
    } catch (err) {
      console.error("Create order error:", err);
      const error = err as { response?: { data?: { message?: string } } };
      setError(
        error.response?.data?.message || "Failed to create order. Please try again."
      );
    } finally {
      setIsLoading(false);
    }
  };

  const copyTrackingNumber = () => {
    if (success) {
      navigator.clipboard.writeText(success.tracking_number);
    }
  };

  const handleNewOrder = () => {
    setSuccess(null);
  };

  // Success state
  if (success) {
    return (
      <Card className="p-8 text-center max-w-2xl mx-auto">
        <div className="w-16 h-16 bg-primary/20 rounded-full flex items-center justify-center mx-auto mb-6">
          <svg
            className="w-8 h-8 text-primary"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M5 13l4 4L19 7"
            />
          </svg>
        </div>
        
        <h2 className="text-2xl font-semibold text-foreground mb-2">
          Order Created Successfully!
        </h2>
        
        <p className="text-muted-foreground mb-6">
          Your package is ready for pickup
        </p>
        
        <div className="bg-muted rounded-lg p-6 mb-6">
          <p className="text-sm text-muted-foreground mb-2">Tracking Number</p>
          <div className="flex items-center justify-center gap-3">
            <p className="text-2xl font-bold text-foreground font-mono">
              {success.tracking_number}
            </p>
            <button
              onClick={copyTrackingNumber}
              className="p-2 hover:bg-accent rounded-lg transition-colors"
              title="Copy tracking number"
            >
              <svg
                className="w-5 h-5 text-muted-foreground"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z"
                />
              </svg>
            </button>
          </div>
          
          <p className="text-sm text-muted-foreground mt-4">
            Price: ₦{success.price.toFixed(2)}
          </p>
        </div>
        
        <Button onClick={handleNewOrder} variant="primary" size="lg">
          Create Another Order
        </Button>
      </Card>
    );
  }

  // Form state
  return (
    <form onSubmit={handleSubmit} className="max-w-3xl mx-auto space-y-8">
      <div>
        <h1 className="text-3xl font-semibold text-foreground mb-2">
          Create New Order
        </h1>
        <p className="text-muted-foreground">
          Fill in the details below to create a delivery request
        </p>
      </div>

      {error && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-lg text-destructive text-sm">
          {error}
        </div>
      )}

      {/* Sender Information */}
      <Card className="p-6">
        <h2 className="text-lg font-semibold text-foreground mb-4">
          Sender Information
        </h2>
        <div className="space-y-4">
          <Input
            label="Sender Name"
            name="sender_name"
            placeholder="Your name"
            value={formData.sender_name}
            onChange={handleChange}
            id="sender_name"
          />
          <Input
            label="Sender Phone"
            name="sender_phone"
            type="tel"
            placeholder="08012345678"
            value={formData.sender_phone}
            onChange={handleChange}
            id="sender_phone"
          />
          <Textarea
            label="Pickup Address"
            name="pickup_address"
            placeholder="Enter pickup location"
            value={formData.pickup_address}
            onChange={handleChange}
            id="pickup_address"
          />
        </div>
      </Card>

      {/* Receiver Information */}
      <Card className="p-6">
        <h2 className="text-lg font-semibold text-foreground mb-4">
          Receiver Information
        </h2>
        <div className="space-y-4">
          <Input
            label="Receiver Name"
            name="receiver_name"
            placeholder="Recipient's name"
            value={formData.receiver_name}
            onChange={handleChange}
            required
            id="receiver_name"
          />
          <Input
            label="Receiver Phone"
            name="receiver_phone"
            type="tel"
            placeholder="08098765432"
            value={formData.receiver_phone}
            onChange={handleChange}
            required
            id="receiver_phone"
          />
          <Textarea
            label="Delivery Address"
            name="delivery_address"
            placeholder="Enter full delivery address"
            value={formData.delivery_address}
            onChange={handleChange}
            required
            id="delivery_address"
          />
        </div>
      </Card>

      {/* Package Details */}
      <Card className="p-6">
        <h2 className="text-lg font-semibold text-foreground mb-4">
          Package Details
        </h2>
        <div className="space-y-4">
          <Textarea
            label="Package Description (Optional)"
            name="package_description"
            placeholder="Brief description of package contents"
            value={formData.package_description}
            onChange={handleChange}
            id="package_description"
          />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Select
              label="Zone"
              name="zone_id"
              options={ZONES}
              value={formData.zone_id || ""}
              onChange={handleChange}
              id="zone_id"
            />
            <Input
              label="Distance (km)"
              name="distance_km"
              type="number"
              step="0.1"
              placeholder="e.g., 15.5"
              value={formData.distance_km || ""}
              onChange={handleChange}
              id="distance_km"
            />
          </div>
        </div>
      </Card>

      {/* Submit Button */}
      <div className="flex justify-end">
        <Button
          type="submit"
          variant="primary"
          size="lg"
          disabled={isLoading}
          className="w-full sm:w-auto"
        >
          {isLoading ? "Creating Order..." : "Create Order"}
        </Button>
      </div>
    </form>
  );
}
